const temperatureThreshold = 40; // Limite de temperatura (40°C)
const liquidLevelThreshold = 100; // Limite de nível de líquido (100 ml)
const actionTopicTemp = "esp32/sub/controletemp"; // Novo tópico de comando de temperatura

// Função para enviar comandos no tópico de controle de temperatura
function sendAction(action) {
    const actionMsg = { action: action };
    node.send({ payload: actionMsg, topic: actionTopicTemp });
}

// Armazena o estado da bomba ligada pelo controle de emergência
let bombaLigadaEmergencia = context.get("bombaLigadaEmergencia") || false;

// Processa mensagens de temperatura
if (msg.topic === "esp32/pub/temperatura") {
    const temperature = parseFloat(msg.payload);

    // Verifica se a temperatura é válida
    if (isNaN(temperature)) {
        return null; // Se não for um número, não faz nada
    }

    // Armazena se a temperatura está alta
    context.set("temperatureHigh", temperature >= temperatureThreshold);

    // Obtém o nível de líquido atual
    const liquidLevel = context.get("liquidLevel") || 0;

    // Liga a bomba se a temperatura estiver alta e o nível de líquido for suficiente, e a bomba não estiver ligada pelo controle de emergência
    if (context.get("temperatureHigh") && liquidLevel >= liquidLevelThreshold && !bombaLigadaEmergencia) {
        sendAction("ligar"); // Envia comando de ligar no tópico de controle de temperatura
        context.set("bombaLigadaEmergencia", true); // Marca que a bomba foi ligada pelo controle de emergência
    } 
    // Desliga a bomba se a temperatura caiu abaixo do limite e a bomba foi ligada pelo controle de emergência
    else if (!context.get("temperatureHigh") && bombaLigadaEmergencia) {
        sendAction("desligar"); // Envia comando de desligar no tópico de controle de temperatura
        context.set("bombaLigadaEmergencia", false); // Marca que a bomba foi desligada pelo controle de emergência
    }

} else if (msg.topic === "esp32/pub/liquido") {
    const liquidLevel = parseInt(msg.payload, 10);

    // Verifica se o nível de líquido é válido
    if (isNaN(liquidLevel)) {
        return null; // Se não for um número, não faz nada
    }

    // Armazena o nível de líquido atual
    context.set("liquidLevel", liquidLevel);

    // Obtém o estado da temperatura
    const temperatureHigh = context.get("temperatureHigh");

    // Liga a bomba se a temperatura estiver alta e o nível de líquido for suficiente, e a bomba não estiver ligada pelo controle de emergência
    if (temperatureHigh && liquidLevel >= liquidLevelThreshold && !bombaLigadaEmergencia) {
        sendAction("ligar"); // Envia comando de ligar no tópico de controle de temperatura
        context.set("bombaLigadaEmergencia", true); // Marca que a bomba foi ligada pelo controle de emergência
    } 
    // Desliga a bomba se o nível de líquido estiver abaixo do limite ou a temperatura estiver normalizada e a bomba foi ligada pelo controle de emergência
    else if ((liquidLevel < liquidLevelThreshold || !temperatureHigh) && bombaLigadaEmergencia) {
        sendAction("desligar"); // Envia comando de desligar no tópico de controle de temperatura
        context.set("bombaLigadaEmergencia", false); // Marca que a bomba foi desligada pelo controle de emergência
    }
}

return null; // Finaliza a função sem retorno

